using namespace std;
int main(){
    int n;
    cin >> n;
    vector<int> nums(n);
    for(int i = 0; i < n; i++) cin >> nums[i];
    int max_profit = 0;
    int min_price = nums[0];
    for(int num : nums){
        min_price = min(min_price, num);
        int profit = num - min_price;
        max_profit = max(max_profit, profit);
    }
    cout << max_profit << endl;
    return 0;
}
